<script setup>import {onMounted,ref,nextTick} from 'vue';import * as echarts from 'echarts';import api from '../api';const data=ref(null),loading=ref(true),trend=ref(),species=ref();const cards=[['users','用户总数','人','+'],['pets','宠物档案','只','◇'],['families','家庭数量','个','⌂'],['healthRecords','健康记录','条','↗']];onMounted(async()=>{try{data.value=await api.get('/dashboard');await nextTick();draw();}finally{loading.value=false;}});function draw(){if(trend.value){const c=echarts.init(trend.value);c.setOption({grid:{left:35,right:10,top:20,bottom:25},xAxis:{type:'category',data:data.value.userTrend.map(x=>x.day),axisLine:{show:false},axisTick:{show:false}},yAxis:{type:'value',splitLine:{lineStyle:{color:'#edf0ec'}}},series:[{type:'line',smooth:true,data:data.value.userTrend.map(x=>x.value),symbolSize:8,lineStyle:{color:'#28705d',width:3},itemStyle:{color:'#28705d'},areaStyle:{color:'rgba(40,112,93,.10)'}}]});}if(species.value){const c=echarts.init(species.value);c.setOption({tooltip:{trigger:'item'},legend:{bottom:0},series:[{type:'pie',radius:['52%','72%'],center:['50%','43%'],label:{show:false},data:data.value.species,itemStyle:{borderColor:'#fff',borderWidth:4},color:['#28705d','#e2a45c','#93b5a9','#d7c3a5']}]});}}</script>
<template><div v-loading="loading"><div class="welcome"><div><p class="eyebrow">TODAY'S OVERVIEW</p><h2>宠物健康运营中心</h2><p>快速掌握平台用户、宠物档案与健康数据的整体状态。</p></div><div class="date-chip">数据实时更新</div></div><div v-if="data" class="stat-grid"><article v-for="c in cards" :key="c[0]" class="stat-card"><div class="stat-icon">{{c[3]}}</div><div><p>{{c[1]}}</p><strong>{{data[c[0]].toLocaleString()}}</strong><small>{{c[2]}}</small></div></article></div><div v-if="data" class="dashboard-grid"><article class="panel trend-panel"><div class="panel-head"><div><h3>新增用户趋势</h3><p>近 7 天注册变化</p></div></div><div ref="trend" class="chart"></div></article><article class="panel"><div class="panel-head"><div><h3>宠物类型分布</h3><p>平台宠物档案构成</p></div></div><div ref="species" class="chart"></div></article></div><article v-if="data" class="panel recent"><div class="panel-head"><div><h3>最近加入的用户</h3><p>最新注册用户概览</p></div><router-link to="/users">查看全部 →</router-link></div><el-table :data="data.recentUsers"><el-table-column prop="id" label="ID" width="90"/><el-table-column label="用户"><template #default="s"><div class="user-cell"><el-avatar :src="s.row.avatar_url">{{s.row.nickname?.slice(0,1)}}</el-avatar><b>{{s.row.nickname||'未设置昵称'}}</b></div></template></el-table-column><el-table-column prop="status" label="状态"><template #default="s"><el-tag type="success" effect="light">{{s.row.status==='ACTIVE'?'正常':s.row.status}}</el-tag></template></el-table-column><el-table-column prop="created_at" label="注册时间"/></el-table></article></div></template>
